calcFn:
var humanTotal = articlesPerMonth * humanCostPerArticle;
    var aiEditCost = articlesPerMonth * aiTimeHrs * hourlyRate;
    var aiTotal = aiToolCost + aiEditCost;
    var savings = humanTotal - aiTotal;
    var timeSaved = articlesPerMonth * (humanTimeHrs - aiTimeHrs);
    var annualSave = savings * 12;
    var annualCost = aiToolCost * 12;
    var roi = (annualSave / annualCost) * 100;
    document.getElementById('humanMonthlyCost').textContent = dollar(humanTotal);
    document.getElementById('aiMonthlyCost').textContent = dollar(aiTotal);
    document.getElementById('monthlySavings').textContent = dollar(savings);
    document.getElementById('timeSaved').textContent = fmt(timeSaved, 0) + ' hours';
    document.getElementById('annualROI').textContent = fmt(roi, 0) + '%';

var totalMinutes = monthlyTickets * avgHandleTime;
    var totalHours = totalMinutes / 60;
    var currentCost = totalHours * agentHourlyRate;
    var deflected = Math.round(monthlyTickets * deflectionRate / 100);
    var remainingTickets = monthlyTickets - deflected;
    var newAgentCost = (remainingTickets * avgHandleTime / 60) * agentHourlyRate;
    var newTotal = newAgentCost + chatbotCost;
    var savings = currentCost - newTotal;
    var yearROI = ((savings * 12) / (chatbotCost * 12)) * 100;
    document.getElementById('currentCost').textContent = dollar(currentCost);
    document.getElementById('ticketsDeflected').textContent = fmt(deflected, 0) + '/month';
    document.getElementById('newCost').textContent = dollar(newTotal);
    document.getElementById('monthlySavings').textContent = dollar(savings);
    document.getElementById('yearlyROI').textContent = fmt(yearROI, 0) + '%';

var laborSaving = hoursAutoPerMonth * laborRate;
    var grossSaving = laborSaving + errorReduction;
    var netSaving = grossSaving - monthlyMaintenance;
    var payback = netSaving > 0 ? implementationCost / netSaving : Infinity;
    var threeYearBenefit = (netSaving * 36) - implementationCost;
    document.getElementById('monthlySavings').textContent = dollar(grossSaving);
    document.getElementById('netMonthlySavings').textContent = dollar(netSaving);
    document.getElementById('paybackMonths').textContent = payback === Infinity ? 'Never' : fmt(payback, 1) + ' months';
    document.getElementById('threeYearROI').textContent = dollar(threeYearBenefit);

var params = parseFloat(modelSize);
    var gpuRate = parseFloat(gpuType);
    var tokens = datasetSize * 1e6;
    var flopsPerToken, gpuFlops, memPerParam;
    if (trainingType === 'finetune') {
      flopsPerToken = params * 1e9 * 2;
      memPerParam = 2;
    } else if (trainingType === 'full') {
      flopsPerToken = params * 1e9 * 6;
      memPerParam = 16;
    } else {
      flopsPerToken = params * 1e9 * 6;
      memPerParam = 16;
      tokens = tokens * 10;
    }
    var totalFlops = flopsPerToken * tokens;
    var gpuTflops = gpuRate <= 2 ? 312e12 : gpuRate <= 4 ? 312e12 : 989e12;
    var effectiveUtil = 0.4;
    var gpuSeconds = totalFlops / (gpuTflops * effectiveUtil);
    var gpuHrs = gpuSeconds / 3600;
    var memNeeded = params * memPerParam;
    var gpuMem = gpuRate <= 2 ? 40 : gpuRate <= 4 ? 80 : 80;
    var numGPU = Math.max(1, Math.ceil(memNeeded / gpuMem));
    var wallHrs = gpuHrs / numGPU;
    var cost = gpuHrs * gpuRate;
    document.getElementById('gpuHours').textContent = fmt(gpuHrs, 1) + ' GPU-hours';
    document.getElementById('numGPUs').textContent = numGPU + ' GPU(s) minimum';
    document.getElementById('totalCost').textContent = dollar(cost);
    document.getElementById('wallTime').textContent = wallHrs >= 24 ? fmt(wallHrs / 24, 1) + ' days' : fmt(wallHrs, 1) + ' hours';

var totalInv = robotCost + installCost;
    var laborSavings = workersReplaced * workerAnnualCost;
    var prodGainValue = laborSavings * (productivityGain / 100);
    var annualBenefit = laborSavings + prodGainValue - annualMaintenance;
    var payback = annualBenefit > 0 ? totalInv / annualBenefit : Infinity;
    var fiveYear = (annualBenefit * 5) - totalInv;
    document.getElementById('totalInvestment').textContent = dollar(totalInv);
    document.getElementById('annualSavings').textContent = dollar(annualBenefit);
    document.getElementById('paybackPeriod').textContent = payback === Infinity ? 'Never' : fmt(payback * 12, 0) + ' months (' + fmt(payback, 1) + ' years)';
    document.getElementById('fiveYearROI').textContent = dollar(fiveYear);

var totalGal = numPeople * numDays * gallonsPerDay;
    var totalLiters = totalGal * 3.785;
    var details, supply, time;
    if (method === 'boil') {
      details = 'Rolling boil for 1 minute (3 min above 6,500 ft)';
      var fuelLbs = totalLiters * 0.1;
      supply = fmt(fuelLbs, 1) + ' lbs firewood or ' + fmt(totalLiters * 0.02, 1) + ' lbs propane';
      time = fmt(totalLiters * 12, 0) + ' minutes total boiling time';
    } else if (method === 'tablets') {
      var tablets = Math.ceil(totalLiters);
      details = '1 tablet per liter, wait 30 minutes';
      supply = tablets + ' purification tablets';
      time = '30 min wait per batch';
    } else if (method === 'filter') {
      details = 'Pump through 0.2 micron filter';
      supply = '1 filter (good for ~1,000L). Yours treats ' + fmt(totalLiters, 0) + 'L';
      time = fmt(totalLiters * 1.5, 0) + ' minutes pumping';
    } else if (method === 'uv') {
      details = 'UV light for 60 seconds per liter (clear water only)';
      supply = fmt(Math.ceil(totalLiters / 80), 0) + ' sets of batteries';
      time = fmt(totalLiters, 0) + ' minutes treatment time';
    } else {
      var drops = totalLiters * 2;
      details = '2 drops unscented bleach (8.25%) per liter, wait 30 min';
      supply = fmt(drops / 20, 1) + ' mL bleach (' + fmt(drops / 20 / 5, 2) + ' teaspoons)';
      time = '30 min wait per batch';
    }
    document.getElementById('totalWater').textContent = fmt(totalGal, 1) + ' gallons (' + fmt(totalLiters, 1) + ' liters)';
    document.getElementById('purifyDetails').textContent = details;
    document.getElementById('fuelOrSupply').textContent = supply;
    document.getElementById('timeRequired').textContent = time;

var totalCal = numPeople * numDays * caloriesPerDay;
    var costPerCal = {freeze: 0.06, canned: 0.01, bulk: 0.004, mixed: 0.02};
    var calPerLb = {freeze: 1800, canned: 600, bulk: 1600, mixed: 1000};
    var shelfYrs = {freeze: '25-30 years', canned: '2-5 years', bulk: '20-30 years', mixed: '5-15 years'};
    var cost = totalCal * (costPerCal[storageType] / 1);
    var weightLbs = totalCal / calPerLb[storageType];
    document.getElementById('totalCalories').textContent = fmt(totalCal, 0) + ' calories';
    document.getElementById('estimatedWeight').textContent = fmt(weightLbs, 0) + ' lbs (' + fmt(weightLbs * 0.454, 0) + ' kg)';
    document.getElementById('estimatedCost').textContent = dollar(cost);
    document.getElementById('shelfLife').textContent = shelfYrs[storageType];

var total = waterLbs + foodLbs + shelterLbs + fireLbs + firstAidLbs + toolsLbs + clothingLbs;
    var pct = (total / bodyWeight) * 100;
    var assessment;
    if (pct <= 15) assessment = 'Excellent — comfortable for most fitness levels';
    else if (pct <= 20) assessment = 'Good — manageable for fit adults';
    else if (pct <= 25) assessment = 'Heavy — may slow you down significantly';
    else assessment = 'Too heavy — reduce weight or improve fitness first';
    var cats = [{n:'Water',w:waterLbs},{n:'Food',w:foodLbs},{n:'Shelter',w:shelterLbs},{n:'Fire/Light',w:fireLbs},{n:'First Aid',w:firstAidLbs},{n:'Tools',w:toolsLbs},{n:'Clothing',w:clothingLbs}];
    cats.sort(function(a,b){return b.w-a.w;});
    var heaviest = cats[0].n + ' (' + fmt(cats[0].w, 1) + ' lbs, ' + fmt(cats[0].w/total*100, 0) + '%)';
    document.getElementById('totalWeight').textContent = fmt(total, 1) + ' lbs (' + fmt(total * 0.454, 1) + ' kg)';
    document.getElementById('bodyPct').textContent = fmt(pct, 1) + '% of body weight';
    document.getElementById('assessment').textContent = assessment;
    document.getElementById('heaviestCategory').textContent = heaviest;

var btuPerCord = parseFloat(woodType) * 1e6;
    var btuPerHour = {heating: 40000, campfire: 15000, cooking: 10000, survival: 25000};
    var totalBTU = btuPerHour[purpose] * hours * numDays;
    var efficiency = purpose === 'heating' ? 0.7 : 0.3;
    var effectiveBTU = totalBTU / efficiency;
    var cords = effectiveBTU / btuPerCord;
    var cubFt = cords * 128;
    var weight = cords * 3500;
    var costPerCord = 250;
    var cost = cords * costPerCord;
    document.getElementById('cordsNeeded').textContent = fmt(cords, 2) + ' cords';
    document.getElementById('cubicFeet').textContent = fmt(cubFt, 0) + ' cu ft';
    document.getElementById('weightLbs').textContent = fmt(weight, 0) + ' lbs';
    document.getElementById('costEstimate').textContent = dollar(cost) + ' (at ~$250/cord)';

var total = fridge + freezer + lights + medical + other;
    var startingWatts = total * 2.5;
    var genSize = Math.ceil(startingWatts / 500) * 500;
    var loadRatio = total / genSize;
    var galPerHour;
    if (fuelType === 'gas' || fuelType === 'dual') galPerHour = (genSize / 3500) * 0.75 * loadRatio;
    else galPerHour = (genSize / 3500) * 1.5 * loadRatio;
    var totalFuel = galPerHour * outageHours;
    var fuelPrice = fuelType === 'propane' ? 3.5 : 3.5;
    var dailyCost = galPerHour * 24 * fuelPrice;
    document.getElementById('totalWatts').textContent = fmt(total, 0) + 'W running / ' + fmt(startingWatts, 0) + 'W starting';
    document.getElementById('generatorSize').textContent = fmt(genSize, 0) + ' watts minimum';
    document.getElementById('fuelNeeded').textContent = fmt(totalFuel, 1) + ' gallons of ' + (fuelType === 'propane' ? 'propane' : 'gasoline');
    document.getElementById('dailyCost').textContent = dollar(dailyCost) + '/day';

var insurance = goodsValue * (insurancePct / 100);
    var cif = goodsValue + freightCost + insurance;
    var duty = cif * (dutyRate / 100);
    var addTariff = goodsValue * (additionalTariff / 100);
    var totalDuties = duty + addTariff;
    var mPF = Math.min(Math.max(cif * 0.003464, 31.67), 614.35);
    var hmf = cif * 0.00125;
    var landed = cif + totalDuties + mPF + hmf;
    var effectiveRate = ((landed - goodsValue) / goodsValue) * 100;
    document.getElementById('cifValue').textContent = dollar(cif);
    document.getElementById('dutyAmount').textContent = dollar(duty) + ' (' + dutyRate + '%)';
    document.getElementById('additionalTariffAmt').textContent = dollar(addTariff) + ' (' + additionalTariff + '%)';
    document.getElementById('totalLanded').textContent = dollar(landed);
    document.getElementById('effectiveRate').textContent = fmt(effectiveRate, 1) + '% total cost increase';

var currentTotal = annualSpend * (1 + currentTariff / 100);
    var altGoods = annualSpend * (1 + altPricePremium / 100);
    var altTotal = altGoods * (1 + altTariff / 100);
    var savings = currentTotal - altTotal;
    var payback = savings > 0 ? transitionCost / savings * 12 : Infinity;
    document.getElementById('currentCost').textContent = dollar(currentTotal);
    document.getElementById('altCost').textContent = dollar(altTotal);
    document.getElementById('annualSavings').textContent = savings > 0 ? dollar(savings) + '/year' : 'No savings (current is cheaper)';
    document.getElementById('paybackPeriod').textContent = payback === Infinity ? 'N/A' : fmt(payback, 1) + ' months';

var importedCost = productCost * (importContent / 100);
    var tariffCost = importedCost * (tariffRate / 100);
    var newCost = productCost + tariffCost;
    var priceIncrease = tariffCost * (passThrough / 100);
    var absorbedCost = tariffCost - priceIncrease;
    var newPrice = sellingPrice + priceIncrease;
    var oldMargin = ((sellingPrice - productCost) / sellingPrice) * 100;
    var newMargin = ((newPrice - newCost) / newPrice) * 100;
    var annualImpact = absorbedCost * unitsPerYear;
    document.getElementById('costIncrease').textContent = '+' + dollar(tariffCost) + ' per unit';
    document.getElementById('newPrice').textContent = dollar(newPrice) + ' (was ' + dollar(sellingPrice) + ')';
    document.getElementById('marginImpact').textContent = fmt(newMargin, 1) + '% (was ' + fmt(oldMargin, 1) + '%)';
    document.getElementById('annualImpact').textContent = '-' + dollar(annualImpact) + ' annual profit loss';

var eligibleDuty = dutyPaid * (exportPct / 100);
    var refundRate = drawbackType === 'lesser' ? 0.95 : 0.99;
    var refund = eligibleDuty * refundRate;
    var netDuty = dutyPaid - refund;
    var effectiveRate = (netDuty / importValue) * 100;
    document.getElementById('eligibleDuty').textContent = dollar(eligibleDuty);
    document.getElementById('refundAmount').textContent = dollar(refund);
    document.getElementById('netDuty').textContent = dollar(netDuty);
    document.getElementById('effectiveRate').textContent = fmt(effectiveRate, 2) + '%';
